/** Limits for various entities. */
export const LIMITS = {
  /** Max messages to include in context for agents */
  AGENT_CONTEXT_MESSAGES: 20,
  /** Legacy default for the previous global lorebook entry cap. Prefer LOREBOOK_ENTRY_LIMIT_* for new code. */
  MAX_LOREBOOK_ENTRIES: 100,
  /** Default max active entries a single lorebook may contribute per generation. */
  LOREBOOK_ENTRY_LIMIT_DEFAULT: 100,
  /** Minimum configurable active-entry limit for a lorebook. */
  LOREBOOK_ENTRY_LIMIT_MIN: 1,
  /** Maximum configurable active-entry limit for a lorebook. */
  LOREBOOK_ENTRY_LIMIT_MAX: 1000,
  /**
   * Default keyword-scan depth (messages back) for the per-turn lorebook scan
   * when neither the entry nor its lorebook sets one. An explicit per-entry or
   * per-lorebook scanDepth of 0 ("scan all") still scans the full history.
   */
  LOREBOOK_DEFAULT_SCAN_DEPTH: 10,
  /** Default global lorebook token budget per generation. 0 means unlimited when explicitly configured per chat. */
  DEFAULT_LOREBOOK_TOKEN_BUDGET: 8192,
  /**
   * Per-active-character lorebook token budget for a single Noodle refresh. Noodle can batch far
   * more characters into one generation call (up to 100, or uncapped with "All invited") than a
   * normal chat turn (1-2 characters), so it scales its own lorebook budget by active character
   * count instead of reusing DEFAULT_LOREBOOK_TOKEN_BUDGET outright — see NOODLE_LOREBOOK_TOKEN_BUDGET_FLOOR.
   */
  NOODLE_LOREBOOK_TOKEN_BUDGET_PER_ACCOUNT: 400,
  /** Minimum Noodle lorebook token budget even for a single active character. */
  NOODLE_LOREBOOK_TOKEN_BUDGET_FLOOR: 1500,
  /** Default summary trigger: every N messages */
  SUMMARY_INTERVAL: 50,
  /** Default vectorization: top-K results */
  VECTOR_TOP_K: 10,
  /** Default recent-message window used to build lorebook vector queries. 0 means all messages. */
  LOREBOOK_VECTOR_QUERY_DEPTH_DEFAULT: 10,
  /** Maximum recent-message window for lorebook vector queries. */
  LOREBOOK_VECTOR_QUERY_DEPTH_MAX: 100,
  /** Default minimum cosine similarity for lorebook vector matches. */
  LOREBOOK_VECTOR_SCORE_THRESHOLD_DEFAULT: 0.3,
  /** Default maximum semantic/vector matches a single lorebook may contribute per generation. */
  LOREBOOK_VECTOR_MAX_RESULTS_DEFAULT: 10,
  /** Minimum maximum semantic/vector matches per lorebook. */
  LOREBOOK_VECTOR_MAX_RESULTS_MIN: 1,
  /** Maximum maximum semantic/vector matches per lorebook. */
  LOREBOOK_VECTOR_MAX_RESULTS_MAX: 100,
  /** Echo Chamber: messages per generation */
  ECHO_CHAMBER_MESSAGES: 5,
} as const;
